    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Keep going northeast toward Forester (216, 114)
  for (let i = 0; i < 3; i++) {
    await click(1100, 150);
    await page.waitForTimeout(4000);

    const state = await page.evaluate(() => {
      const s = window.__latestGameState;
      const f = s.nearby_entities.find(e => e.name === 'Forester');
      return { pos: s.player_position, hp: s.player_stats.hp, dist: f ? f.distance : null };
    });

    if (state.dist && state.dist <= 5) break;
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    const f = s.nearby_entities.find(e => e.name === 'Forester');
    return JSON.stringify({ pos: s.player_position, hp: s.player_stats.hp, forester: f ? { dist: f.distance, on_screen: f.on_screen, click_x: f.click_x, click_y: f.click_y } : null });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return finalState;
}

