async (page) => {
  // Forester is at (216,114), player at (218,112) - 2 tiles west + 2 tiles south
  // Canvas center ~(640,360) = player position
  // Forester screen approx: (640 - 2*48, 360 + 2*32) = (544, 424)
  const click = (x, y) => page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // First walk toward Forester
  await click(544, 424);
  await page.waitForTimeout(2000);

  // Check position
  const pos = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return gs ? JSON.stringify({pos: gs.player_position, nearby: (gs.nearby_entities||[]).slice(0,3).map(e=>({name:e.name,dist:e.distance,qnpc:e.quest_npc}))}) : 'no state';
  });
  return pos;
}

