async (page) => {
  const walkToForester = async () => {
    for (let i = 0; i < 5; i++) {
      const info = await page.evaluate(() => {
        const gs = window.__latestGameState;
        const f = (gs?.nearby_entities||[]).find(e=>e.name==='Forester');
        if (!f) return null;
        const dx = f.x - gs.player_position.x, dy = f.y - gs.player_position.y;
        return {dist: f.distance, sx: 640+dx*48, sy: 360+dy*48};
      });
      if (!info || info.dist <= 2) break;
      const sx = Math.max(50, Math.min(1230, info.sx));
      const sy = Math.max(50, Math.min(670, info.sy));
      await page.evaluate(({sx,sy}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: sx, clientY: sy, bubbles: true }));
      }, {sx, sy});
      await page.waitForTimeout(2500);
    }
  };

  await walkToForester();

  const dist = await page.evaluate(() => {
    const f = (window.__latestGameState?.nearby_entities||[]).find(e=>e.name==='Forester');
    return {dist: f?.distance, pos: window.__latestGameState?.player_position};
  });
  return JSON.stringify(dist);
}

