async (page) => {
  const click = async (x, y) => {
    await page.evaluate(({x, y}) => {
      window.game.input.isOnCanvas = true;
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, {x, y});
  };

  // Combat loop - attack rats for XP
  for (let i = 0; i < 5; i++) {
    const state = await page.evaluate(() => {
      const gs = window.__latestGameState;
      if (!gs) return null;
      const mobs = (gs.nearby_entities||[]).filter(e=>e.type===3 && e.on_screen && e.distance<=5);
      return { hp: gs.player_stats?.hp, max_hp: gs.player_stats?.max_hp, level: gs.player_stats?.level, mobs };
    });
    if (!state) break;

    // Heal if needed
    if (state.hp < state.max_hp * 0.5) {
      const inv = await page.evaluate(() => window.__latestGameState?.inventory || []);
      const food = inv.find(i => i.edible);
      if (food) {
        await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), food.slot);
        await page.waitForTimeout(500);
      }
    }

    if (state.mobs.length > 0) {
      const mob = state.mobs[0];
      await click(mob.cx, mob.cy);
      await page.waitForTimeout(6000);
    } else {
      // No nearby mobs, wait
      await page.waitForTimeout(3000);
    }
  }

  const finalState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    if (!gs) return JSON.stringify({error: 'no state'});
    return JSON.stringify({
      pos: gs.player_position,
      hp: gs.player_stats?.hp,
      max_hp: gs.player_stats?.max_hp,
      level: gs.player_stats?.level,
      skill3xp: window.game?.player?.skills?.[3]?.experience || 0,
      mobs: (gs.nearby_entities||[]).filter(e=>e.type===3).slice(0,4).map(e=>({name:e.name,dist:e.distance,cx:e.click_x,cy:e.click_y,on_screen:e.on_screen})),
      drops: (gs.nearby_entities||[]).filter(e=>e.type===4).slice(0,3).map(e=>({name:e.name,dist:e.distance,cx:e.click_x,cy:e.click_y})),
      inv: gs.inventory?.slice(0,8).map(e=>({slot:e.slot,name:e.name,count:e.count,edible:e.edible,equippable:e.equippable}))
    });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return finalState;
}

