async (page) => {
  const click = async (x, y) => {
    await page.evaluate(({x, y}) => {
      window.game.input.isOnCanvas = true;
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, {x, y});
  };

  const positions = [];

  // Strategy: go south first (y increases), then west, then north to portal
  // Portal target: (123, 140). Use smaller steps.
  const waypoints = [
    [135, 155],  // go south
    [125, 155],  // go west
    [123, 148],  // go northwest
    [123, 143],  // go north closer to portal
    [123, 141],  // adjacent to portal
  ];

  for (const [wx, wy] of waypoints) {
    for (let i = 0; i < 5; i++) {
      const curr = await page.evaluate(() => ({ x: window.game.player.gridX, y: window.game.player.gridY }));
      const dist = Math.abs(wx - curr.x) + Math.abs(wy - curr.y);
      if (dist <= 2) break;

      const cx = (wx - curr.x) * 48 + 640;
      const cy = (wy - curr.y) * 48 + 360;
      await click(Math.max(50, Math.min(1230, cx)), Math.max(50, Math.min(680, cy)));
      await page.waitForTimeout(3000);
    }

    const curr = await page.evaluate(() => ({ x: window.game.player.gridX, y: window.game.player.gridY }));
    positions.push(`wp(${wx},${wy})->actual(${curr.x},${curr.y})`);
  }

  const state = await page.evaluate(() => {
    const p = window.game.player;
    return JSON.stringify({ pos: {x:p.gridX, y:p.gridY} });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return positions.join(', ') + ' | ' + state;
}

